module tb_trojan_2;

  reg clk, reset_n, cs, we;
  reg [7:0] address;
  reg [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0] addr;
    input [31:0] data;
    begin
