      cs = 1; we = 1;
      address = addr;
      write_data = data;
      #20;
      cs = 0; we = 0;
    end
  endtask

  task read_word;
    input [7:0] addr;
    output [31:0] data;
    begin
      @(negedge clk);
      cs = 1; we = 0;
      address = addr;
      #20;
      data = read_data;
      cs = 0;
    end
  endtask

  reg [31:0] rdata;
